B.af7=new A.uV("Ch\u01b0\u01a1ng 1 - R\u1eebng T\xe2n Th\u1ee7","R\u1eebng c\u0169 v\u1eabn xanh, ch\u1ec9 l\xf2ng ng\u01b0\u1eddi \u0111\xe3 \u0111\u1ed5i m\xe0u. Ta tr\u1edf l\u1ea1i n\u01a1i nh\u1eadp m\xf4n n\u0103m x\u01b0a sau l\u1ec5 tang song th\xe2n \u0111\xe3 m\xe3n th\u1ecd, kh\xf4ng c\xf2n l\xe0 \u0111\u1ec7 t\u1eed c\u0169 m\xe0 l\xe0 k\u1ebb s\u1ed1ng s\xf3t \u0111i gi\u1eef l\u1eddi h\u1ee9a mu\u1ed9n v\u1edbi gia \u0111\xecnh.")
B.af8=new A.uV("Ch\u01b0\u01a1ng 2 - T\xe0n T\xedch Vi\xeam","T\xe0n t\xedch n\xe0y ch\xe1y kh\xf4ng ch\u1ec9 b\u1edfi l\u1eeda, m\xe0 b\u1edfi cu\u1ed9c tranh \u0111o\u1ea1t Linh M\u1ea1ch Vi\xeam T\xe2m gi\u1eefa th\u01b0\u01a1ng h\u1ed9i v\xe0 n\u1ed9i ph\u1ea3n trong c\xe1c t\xf4ng m\xf4n. Ta \u0111i s\xe2u v\xe0o tro t\xe0n \u0111\u1ec3 l\u1ea5y ch\u1ee9ng c\u1ee9 cu\u1ed1i, v\u1ea1ch r\xf5 ai \u0111\xe3 ch\xe2m ng\xf2i chi\u1ebfn cu\u1ed9c h\u1ee7y di\u1ec7t t\xf4ng m\xf4n c\u1ee7a ta.")
B.af5=new A.uV("Ch\u01b0\u01a1ng 3 - \u0110\xe1y Bi\u1ec3n Enkavia","Bi\u1ec3n s\xe2u Enkavia c\u1ea5t gi\u1eef phong \u1ea5n k\xfd \u1ee9c v\u1ec1 to\xe0n b\u1ed9 v\u1ee5 ph\u1ea3n b\u1ed9i. N\u1ebfu m\u1edf \u0111\u01b0\u1ee3c phong \u1ea5n n\xe0y v\xe0 c\xf4ng b\u1ed1 tr\u01b0\u1edbc thi\xean h\u1ea1, ta c\xf3 th\u1ec3 kh\xe9p l\u1ea1i v\xf2ng l\u1eb7p ch\xe9m gi\u1ebft, m\u1edf ra m\u1ed9t tr\u1eadt t\u1ef1 m\u1edbi n\u01a1i k\u1ebb y\u1ebfu kh\xf4ng c\xf2n b\u1ecb \u0111em l\xe0m v\u1eadt hi sinh.")
